@import './_var.less';

.button() {
  position: relative;
  z-index: 0;
  overflow: hidden;
  font-size: @btn-font-default;
  outline: none;
  border-width: @btn-border-width;
  border-style: solid;
  border-color: transparent;
  background-color: transparent;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  vertical-align: middle;
  white-space: nowrap;
  border-radius: @btn-border-radius;
  transition: all @anim-duration-base linear;
  touch-action: manipulation;
}

.button-size(@btn-height, @btn-font-size, @btn-icon-size, @padding-horizontal) {
  height: @btn-height;
  font: @btn-font-size;
  padding-left: calc(@padding-horizontal - @btn-border-width);
  padding-right: calc(@padding-horizontal - @btn-border-width);

  .t-icon,
  .@{prefix}-loading {
    font-size: @btn-icon-size;
  }
}

@import "variables";
@import "ui-variables";

.sheet-toolbar{
  .item-back{
    padding-top: 15px;
    img.content-mask{
      background-color: @sidebar-fg-color;
    }
    .item-back-title{
      color: @sidebar-fg-color;
    }
  }
}

.preferences-wrap {
  .preferences-sidebar, .container-preference-tabs .preferences-tabs {
    .item {
      border-bottom: none;
      color: @white;
      &.active {
        font-weight: bold;
        font-size: 1.2rem;
        background: @sidebar-active-item-bg !important;
        .name {
          color: @white !important;
        }
      }
    }
  }
}

.nylas-editable-list .items-wrapper .selected.editing{
  background: @sidebar-bg-hl;
}
.nylas-editable-list .items-wrapper .selected, .nylas-editable-list:focus .items-wrapper .selected {
  background: @sidebar-active-item-bg;
}

// Retainers resizer bar in heap snapshot
.heap-snapshot-view .heap-snapshot-view-resizer {
	background-color: @global-toolbar !important;
	border-top: 1px solid @global-divider !important;
	border-bottom: 1px solid @global-divider !important;
	color: @global-text;
}

// Heap snapshot table text
#profile-views .data-container .object-column {
	color: @global-text;

	button {
		.button-styles();
	}
}

.heap-snapshot-view tr:not(.selected) td.object-column span.highlight {
	background-color: @selection-background !important;
	border-radius: 3px;
}

.profile-sidebar-tree-item,
.profile-launcher-view-tree-item,
.heap-snapshot-sidebar-tree-item {
	color: @global-text !important;
}

.source-code.event-properties .name {
	color: @js-obj-name !important;
}

.profile-launcher-target-list {
	border: 1px solid @global-divider !important;
}

.profile-isolate-item {
	&:hover {
		.highlight(hover)
	}

	&.selected {
		border-color: transparent !important;
		.highlight(selection)
	}
}

// border-radius

.border-top-radius(@radius) {
  border-top-right-radius: @radius;
  border-top-left-radius: @radius;
  -moz-border-radius-topright:@radius;
  -moz-border-radius-topleft:@radius;
  -webkit-border-top-right-radius:@radius;
  -webkit-border-top-left-radius:@radius;
}

.border-right-radius(@radius) {
  border-bottom-right-radius: @radius;
  border-top-right-radius: @radius;
  -moz-border-radius-bottomright:@radius;
  -moz-border-radius-topright:@radius;
  -webkit-border-top-right-radius:@radius;
  -webkit-border-bottom-right-radius:@radius;
}

.border-bottom-radius(@radius) {
  border-bottom-right-radius: @radius;
  border-bottom-left-radius: @radius;
  -moz-border-radius-bottomleft:@radius;
  -moz-border-radius-bottomright:@radius;
  -webkit-border-bottom-right-radius:@radius;
  -webkit-border-bottom-left-radius:@radius;
}

.border-left-radius(@radius) {
  border-bottom-left-radius: @radius;
  border-top-left-radius: @radius;
  -moz-border-radius-bottomleft:@radius;
  -moz-border-radius-topleft:@radius;
  -webkit-border-top-left-radius:@radius;
  -webkit-border-bottom-left-radius:@radius;
}

@import "colors";

// This defines all syntax variables that syntax themes must implement when they
// include a syntax-variables.less file.

// General colors
@syntax-text-color: @very-light-gray;
@syntax-cursor-color: @white;
@syntax-selection-color: #1d508d;
@syntax-background-color: @very-dark-gray;

// Guide colors
@syntax-wrap-guide-color: @dark-gray;
@syntax-indent-guide-color: @gray;
@syntax-invisible-character-color: @gray;

// For find and replace markers
@syntax-result-marker-color: @light-gray;
@syntax-result-marker-color-selected: white;

// Gutter colors
@syntax-gutter-text-color: @very-light-gray;
@syntax-gutter-text-color-selected: @syntax-gutter-text-color;
@syntax-gutter-background-color: lighten(@syntax-background-color, 2%);
@syntax-gutter-background-color-selected: lighten(@syntax-background-color, 10%);

// For git diff info. i.e. in the gutter
@syntax-color-renamed: @blue;
@syntax-color-added: @green;
@syntax-color-modified: @orange;
@syntax-color-removed: @red;

